import React from 'react';
import { Path, G, Rect } from 'react-native-svg';

export interface TreeProps {
  x: number;
  y: number;
  scale?: number;
  opacity?: number;
  type?: number;
}

export const Tree: React.FC<TreeProps> = ({ x, y, scale = 1, opacity = 1, type = 1 }) => {
  return (
    <G transform={`translate(${x}, ${y}) scale(${scale})`} opacity={opacity}>
      {type === 1 && <RoundTree3 />}
      {type === 2 && <RoundTree2 />}
      {type === 3 && <RoundTree1 />}
      {type === 4 && <PineTreeFull />}
      {type === 5 && <PineTree2Tier />}
      {type === 6 && <PineTreeSimple />}
      {type === 7 && <RoundTreeAlt />}
      {type === 8 && <TeardropSingle />}
      {type === 9 && <TeardropDouble />}
      {type === 10 && <TeardropTriple />}
      {type === 11 && <BushySmall />}
      {type === 12 && <BushyLarge />}
      {type === 13 && <BushyMedium />}
      {type === 14 && <VineTreeSmall />}
      {type === 15 && <VineTreeLarge />}
      {type === 16 && <VineTreeMedium />}
      {type === 17 && <ClusterTreeSmall />}
      {type === 18 && <ClusterTreeMedium />}
    </G>
  );
};

